var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"바이탈 체크…! 체온, 호흡, 맥박, 혈압 모두 불안정합니다!","JPN":"バイタルチェック……！　体温、呼吸、脈、血圧、全部不安定です！","ENG":"Checking vitals...! Body temperature, breathing, pulse, and blood pressure all unstable!","TWN":"生命徵兆檢查…！體溫、呼吸、脈搏、血壓都不穩定！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"안정화 시도하고 마취의 대기시켜! 여차하면 응급 수술 들어가야 해!","JPN":"安定化を試みて、麻酔医の待機を！　いざとなれば緊急手術だ！","ENG":"Begin stabilization! Prep the anesthesia! If it gets worse, we'll need emergency surgery!","TWN":"嘗試穩定病情，準備麻醉！如果情況緊急，就要進行緊急手術！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"주교님의 상태는 어떤가요?","JPN":"主教の状態はいかがですか？","ENG":"How is the Bishop?","TWN":"主教的狀態怎麼樣？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_PRIDE_NULL_NULL","text":{"KOREA":"고비는 넘기셨지만 아직 의식이 불분명하십니다.","JPN":"危険な状態は脱しましたが、まだ意識がはっきりとしていません。","ENG":"He's past the worst of it, but still unconscious.","TWN":"雖然度過了危機，但意識仍然不清晰。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOCTOR_PRIDE_NULL_NULL","text":{"KOREA":"당분간은… 상태를 지켜봐야 할 것 같군요.","JPN":"しばらくは……様子見ですね。","ENG":"We'll have to... keep monitoring him for now.","TWN":"暫時……還是觀察一下情況吧。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_PRIDE_NULL_NULL","text":{"KOREA":"메데이아 경, 괜찮으십니까?","JPN":"メデイア卿、大丈夫ですか？","ENG":"Dame Medea, are you all right?","TWN":"美狄亞，你沒事吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아무것도 아닙니다. 수술, 고생 많으셨어요.","JPN":"何でもありません。手術、お疲れ様でした。","ENG":"Don't mind me. You've done well with the surgery.","TWN":"沒什麼。手術，辛苦了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"주교님이 의식을 되찾으시면 제게 연락 부탁드립니다.","JPN":"主教が意識を取り戻したら、私にご連絡をお願いします。","ENG":"Please contact me as soon as the Bishop regains consciousness.","TWN":"請在主教恢復意識後聯絡我。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……하.","JPN":"……は。","ENG":"*...Sigh*","TWN":"……哈。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"본부에 배신자가 있었다고요?","JPN":"本部に裏切り者がいた？","ENG":"You're telling me there was a traitor inside HQ?","TWN":"本部還有背叛者嗎？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그래. 이전부터 레드시프트와 긴밀한 관계를 유지한 모양일세.","JPN":"ああ。昔からレッドシフトと緊密な関係を維持していたようだ。","ENG":"Yes. It seems they've maintained close ties with Red Shift for some time.","TWN":"是啊，看起來從以前開始就和紅移保持著密切的關係。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"작전 유출과 작전 팀의 채널 송신 차단도 그들의 개입이었던 모양이야.","JPN":"作戦の流出と作戦チームのチャンネル送信遮断も、彼らの介入だったらしい。","ENG":"They were behind both the leaked plans and the jamming of the operation team's comms.","TWN":"作戰洩露和作戰隊的頻道發送阻斷似乎也是他們的介入。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그걸 지금…… 말이라고 하시는 건가요?","JPN":"冗談でしょう？","ENG":"And you're... just now telling me this?!","TWN":"你……怎麼可以這麼說呢？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이번 작전에 사활이 걸려있단 걸 아시면서 그런 무책임한 소리를…!!","JPN":"今回の作戦に生死がかかっていると知りながら、そんな無責任な話……！！","ENG":"You knew this operation was everything, and yet you speak so carelessly...!!","TWN":"明知道這次作戰關乎生死，你怎麼能說出這麼不負責任的話…！！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"글쎄. 이제 와서는 의문이 드는군.","JPN":"どうだか。今になっては疑問だ。","ENG":"Well. At this point, I have to wonder.","TWN":"這個嘛，現在才開始覺得疑惑。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"만약 작전대로 풀렸다면 우리가 이길 수 있었을까?","JPN":"もし作戦どおりになっていたら、私たちは勝利できただろうか？","ENG":"Even if things had gone according to plan, could we really have won?","TWN":"如果按照計畫進行，我們能贏嗎？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...What?","TWN":"……嗯？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"기사단은 그림자 전문이나 그것이 인간을 죽이는데 능통하다는 것은 아니야.","JPN":"騎士団はシャドウ専門だが、それが人間を殺すことに長けているという意味ではない。","ENG":"The Order specializes in killing Shadows, not humans.","TWN":"騎士團擅長對付暗影，但這並不意味著他們擅長殺人。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"지키는 입장에 선 기사가 어찌 생사결을 벌일 수 있겠나?","JPN":"守る立場にある騎士が、はたして生死を決する戦いをこなせるだろうか。","ENG":"How can a knight, sworn to protect, engage in a duel to the death?","TWN":"站在守護立場的騎士怎麼能進行生死決鬥呢？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"처음부터 이 싸움 자체가 단원들에게 무거운 짐이었던 거야.","JPN":"最初からこの戦い自体が、団員には荷が重かったのだよ。","ENG":"This war has been a burden from the very start.","TWN":"從一開始，這場戰鬥對成員們來說就是沉重的負擔。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"프레이더 경. 지금 레드시프트에게 투항하자는 겁니까?","JPN":"フレイダー卿。今、レッドシフトに投降しようというのですか？","ENG":"Sir Frayder. Are you suggesting we surrender to Red Shift?","TWN":"弗雷德。你是說現在要向紅移投降嗎？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그들의 목적은 기사단이 아니야. 별의 무구일 뿐이지.","JPN":"彼らの目的は騎士団ではない。星の武具だ。","ENG":"Their goal isn't the Order. It's the Star Armaments.","TWN":"他們的目的不是騎士團，而是星之武具。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"설령 기사단이 추구해온 정의에 위반되는 일이라 한들.","JPN":"たとえ騎士団が追求してきた正義に反することであっても。","ENG":"Even if that goes against the justice we've upheld...","TWN":"即便是違反了騎士團所追求的正義之事。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"후일을 위해 일보 후퇴하는 것을, 현 시점에서 어찌 고려하지 않겠는가?","JPN":"後日のための一歩後退を、現時点で考慮しない理由はない。","ENG":"Shouldn't we at least consider a tactical retreat, for the future's sake?","TWN":"為了將來而暫時退一步，現階段怎麼能不考慮呢？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};